{
  "version": "arkpilot-uitree/v2",
  "kind": "semantic-ui-protocol",
  "appName": "今天吃什么",
  "targetDevice": {
    "widthVp": 1272,
    "heightVp": 2756,
    "contentMaxWidthVp": 420
  },
  "surfaces": [
    {
      "id": "home-page",
      "surfaceId": "home",
      "pageId": "home-page",
      "name": "首页",
      "route": "pages/Home",
      "tabId": "tab-home",
      "semanticTargets": [
        {
          "id": "home-spin-button",
          "role": "action",
          "event": "spin-wheel"
        },
        {
          "id": "home-wheel-result",
          "role": "assertion",
          "binding": "/wheel/selectedDish"
        },
        {
          "id": "home-result-view-button",
          "role": "action",
          "event": "open-dish-detail",
          "context": { "source": "wheel-result" }
        },
        {
          "id": "home-spin-again-button",
          "role": "action",
          "event": "spin-wheel"
        },
        {
          "id": "home-wheel-settings-button",
          "role": "action",
          "event": "open-wheel-settings"
        },
        {
          "id": "home-quick-checkin-button",
          "role": "action",
          "event": "open-checkin-form",
          "context": { "source": "home-quick" }
        }
      ]
    },
    {
      "id": "ingredients-page",
      "surfaceId": "ingredients",
      "pageId": "ingredients-page",
      "name": "食材推荐",
      "route": "pages/Ingredients",
      "tabId": "tab-ingredients",
      "semanticTargets": [
        {
          "id": "ingredients-input",
          "role": "input",
          "event": "add-ingredient"
        },
        {
          "id": "ingredients-add-button",
          "role": "action",
          "event": "add-ingredient"
        },
        {
          "id": "ingredients-list",
          "role": "list",
          "binding": "/ingredients",
          "itemIdPattern": "ingredient-item-{id}",
          "emptyStateId": "ingredients-empty-state"
        },
        {
          "id": "ingredients-clear-button",
          "role": "action",
          "event": "clear-ingredients"
        },
        {
          "id": "ingredients-recommend-list",
          "role": "list",
          "binding": "/ingredients/recommendations",
          "itemIdPattern": "ingredients-dish-{id}",
          "emptyStateId": "ingredients-recommend-empty-state"
        },
        {
          "id": "ingredients-recommend-checkin-button",
          "role": "action",
          "event": "open-checkin-form",
          "context": { "source": "ingredients-recommend" }
        }
      ]
    },
    {
      "id": "discover-page",
      "surfaceId": "discover",
      "pageId": "discover-page",
      "name": "发现",
      "route": "pages/Discover",
      "tabId": "tab-discover",
      "semanticTargets": [
        {
          "id": "discover-mood-filter",
          "role": "input",
          "event": "filter-mood",
          "binding": "/discover/selectedMoods"
        },
        {
          "id": "discover-time-filter",
          "role": "input",
          "event": "filter-time",
          "binding": "/discover/selectedTimes"
        },
        {
          "id": "discover-reset-button",
          "role": "action",
          "event": "reset-filters"
        },
        {
          "id": "discover-result-list",
          "role": "list",
          "binding": "/discover/results",
          "itemIdPattern": "discover-dish-{id}",
          "emptyStateId": "discover-empty-state"
        }
      ]
    },
    {
      "id": "checkin-page",
      "surfaceId": "checkin",
      "pageId": "checkin-page",
      "name": "打卡",
      "route": "pages/Checkin",
      "tabId": "tab-checkin",
      "semanticTargets": [
        {
          "id": "checkin-add-button",
          "role": "action",
          "event": "open-checkin-form"
        },
        {
          "id": "checkin-today-count",
          "role": "assertion",
          "binding": "/checkin/todayCount"
        },
        {
          "id": "checkin-today-calories",
          "role": "assertion",
          "binding": "/checkin/todayCalories"
        },
        {
          "id": "checkin-timeline-list",
          "role": "list",
          "binding": "/checkin/today",
          "itemIdPattern": "checkin-item-{id}",
          "emptyStateId": "checkin-empty-state"
        },
        {
          "id": "checkin-edit-button",
          "role": "action",
          "event": "edit-checkin"
        },
        {
          "id": "checkin-delete-button",
          "role": "action",
          "event": "delete-checkin"
        },
        {
          "id": "checkin-share-button",
          "role": "action",
          "event": "open-share-card",
          "context": { "source": "checkin" }
        }
      ]
    },
    {
      "id": "share-card-page",
      "surfaceId": "share-card",
      "pageId": "share-card-page",
      "name": "分享卡片",
      "route": "pages/ShareCard",
      "semanticTargets": [
        {
          "id": "share-card-preview",
          "role": "assertion",
          "binding": "/share/cardData"
        },
        {
          "id": "share-template-selector",
          "role": "input",
          "event": "select-template",
          "binding": "/share/selectedTemplate"
        },
        {
          "id": "share-save-button",
          "role": "action",
          "event": "save-card"
        },
        {
          "id": "share-share-button",
          "role": "action",
          "event": "share-card"
        }
      ]
    },
    {
      "id": "dish-detail-page",
      "surfaceId": "dish-detail",
      "pageId": "dish-detail-page",
      "name": "菜品详情",
      "route": "pages/DishDetail",
      "semanticTargets": [
        {
          "id": "dish-detail-title",
          "role": "assertion",
          "binding": "/dish/name"
        },
        {
          "id": "dish-detail-checkin-button",
          "role": "action",
          "event": "open-checkin-form",
          "context": { "source": "dish-detail" }
        },
        {
          "id": "dish-detail-share-button",
          "role": "action",
          "event": "open-share-card",
          "context": { "source": "dish-detail" }
        }
      ]
    },
    {
      "id": "profile-page",
      "surfaceId": "profile",
      "pageId": "profile-page",
      "name": "我的",
      "route": "pages/Profile",
      "tabId": "tab-profile",
      "semanticTargets": [
        {
          "id": "profile-custom-dishes-list",
          "role": "list",
          "binding": "/profile/customDishes",
          "itemIdPattern": "profile-custom-dish-{id}",
          "emptyStateId": "profile-custom-dishes-empty-state"
        },
        {
          "id": "profile-add-custom-dish-button",
          "role": "action",
          "event": "add-custom-dish"
        },
        {
          "id": "profile-clear-data-button",
          "role": "action",
          "event": "clear-all-data"
        }
      ]
    },
    {
      "id": "checkin-form-sheet",
      "surfaceId": "checkin-form",
      "pageId": "checkin-form-sheet",
      "name": "打卡表单",
      "route": "pages/CheckinForm",
      "semanticTargets": [
        {
          "id": "checkin-form-meal-picker",
          "role": "input",
          "event": "select-meal",
          "binding": "/checkinForm/meal"
        },
