          "id": "checkin-form-dish-search",
          "role": "input",
          "event": "search-dish",
          "binding": "/checkinForm/dishQuery"
        },
        {
          "id": "checkin-form-note-input",
          "role": "input",
          "binding": "/checkinForm/note"
        },
        {
          "id": "checkin-form-submit-button",
          "role": "action",
          "event": "submit-checkin"
        },
        {
          "id": "checkin-form-cancel-button",
          "role": "action",
          "event": "cancel-checkin-form"
        }
      ]
    },
    {
      "id": "wheel-settings-sheet",
      "surfaceId": "wheel-settings",
      "pageId": "wheel-settings-sheet",
      "name": "转盘设置",
      "route": "pages/WheelSettings",
      "semanticTargets": [
        {
          "id": "wheel-settings-input",
          "role": "input",
          "binding": "/wheelSettings/newDishName"
        },
        {
          "id": "wheel-settings-add-button",
          "role": "action",
          "event": "add-wheel-dish"
        },
        {
          "id": "wheel-settings-list",
          "role": "list",
          "binding": "/wheelSettings/customDishes",
          "itemIdPattern": "wheel-settings-dish-{id}",
          "emptyStateId": "wheel-settings-empty-state"
        },
        {
          "id": "wheel-settings-reset-button",
          "role": "action",
          "event": "reset-wheel-dishes"
        }
      ]
    }
  ],
  "events": [
    { "name": "spin-wheel", "description": "触发转盘旋转并随机选择菜品" },
    { "name": "open-dish-detail", "description": "打开菜品详情页" },
    { "name": "open-wheel-settings", "description": "打开转盘自定义设置" },
    { "name": "add-wheel-dish", "description": "添加自定义转盘菜品" },
    { "name": "reset-wheel-dishes", "description": "重置转盘菜品为默认" },
    { "name": "add-ingredient", "description": "添加冰箱食材" },
    { "name": "clear-ingredients", "description": "清空冰箱食材" },
    { "name": "filter-mood", "description": "选择心情筛选标签" },
    { "name": "filter-time", "description": "选择用餐时段筛选标签" },
    { "name": "reset-filters", "description": "重置发现页筛选条件" },
    { "name": "open-checkin-form", "description": "打开打卡表单" },
    { "name": "submit-checkin", "description": "提交打卡记录" },
    { "name": "cancel-checkin-form", "description": "取消打卡表单" },
    { "name": "edit-checkin", "description": "编辑打卡记录" },
    { "name": "delete-checkin", "description": "删除打卡记录" },
    { "name": "open-share-card", "description": "打开分享卡片页" },
    { "name": "select-template", "description": "切换分享卡片模板" },
    { "name": "save-card", "description": "保存卡片到相册" },
    { "name": "share-card", "description": "调用系统分享卡片" },
    { "name": "add-custom-dish", "description": "添加全局自定义菜品" },
    { "name": "clear-all-data", "description": "清空所有本地数据" }
  ],
  "bindings": [
    { "path": "/wheel/selectedDish", "type": "Dish | null" },
    { "path": "/wheel/isSpinning", "type": "boolean" },
    { "path": "/ingredients", "type": "Ingredient[]" },
    { "path": "/ingredients/recommendations", "type": "Dish[]" },
    { "path": "/discover/selectedMoods", "type": "string[]" },
    { "path": "/discover/selectedTimes", "type": "string[]" },
    { "path": "/discover/results", "type": "Dish[]" },
    { "path": "/checkin/today", "type": "Checkin[]" },
    { "path": "/checkin/todayCount", "type": "number" },
    { "path": "/checkin/todayCalories", "type": "number" },
    { "path": "/checkinForm/meal", "type": "MealType" },
    { "path": "/checkinForm/dishQuery", "type": "string" },
    { "path": "/checkinForm/note", "type": "string" },
    { "path": "/share/cardData", "type": "ShareCardData" },
    { "path": "/share/selectedTemplate", "type": "string" },
    { "path": "/dish/name", "type": "string" },
    { "path": "/profile/customDishes", "type": "Dish[]" },
    { "path": "/wheelSettings/customDishes", "type": "Dish[]" }
  ]
}

